def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        if item < 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if item == 0:
            if capacity > 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
            continue
        score = 0.0
        decay = 1.0
        boost = 1.0
        if ratio > 5:
            for n in range(1, 10):
                exp_part = np.exp(ratio / (n + 1))
                score += ((-1) ** n) * exp_part / (n ** 2 + 1)
            boost = ratio ** 1.8
            for j in range(1, 5):
                decay *= (1 - 1 / (ratio + j + 1))
            priorities[i] = abs(score) * boost * decay * 1.5
        elif 3 < ratio <= 5:
            sum1 = 0
            sum2 = 1
            for x in range(1, 15):
                val = (ratio ** x) / (x ** 3 + 1)
                if x % 3 == 0:
                    sum1 += val
                elif x % 4 == 0:
                    sum1 -= val / 2
                else:
                    sum1 += val / 3
                sum2 += 1 / (ratio + x + 2)
            priorities[i] = abs(sum1) * (sum2 ** 0.7) * 3
        elif 1.5 < ratio <= 3:
            temp_sum = 0
            for p in range(1, 20):
                sign = (-1) ** (p)
                temp_sum += sign * (ratio ** p) / (p * (p + 2))
            if ratio < 2:
                multiplier = 30
            elif ratio < 2.5:
                multiplier = 20
            else:
                multiplier = 15
            penalty = 0
            for q in range(1, 8):
                penalty += (ratio ** q) / ((q + 1) ** 2 + 1)
            priorities[i] = abs(temp_sum) * multiplier + penalty * 2
        elif 0 < ratio <= 1.5:
            s1 = 0
            s2 = 0
            for r in range(1, 25):
                if r % 5 == 0:
                    s1 += (ratio ** r) / (r * 4)
                elif r % 2 == 0:
                    s1 -= (ratio ** r) / (r * 3)
                else:
                    s1 += (ratio ** r) / (r * 6)
                s2 += np.sin(ratio * r) / (r + 1)
            factor1 = 25 if ratio < 0.5 else 15 if ratio < 1 else 8
            factor2 = abs(s2) * 10
            priorities[i] = abs(s1) * factor1 + factor2
        else:
            if item == 0 and capacity > 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] != np.inf and capacity > 0:
            adjust = 1.0
            for z in range(1, 5):
                adjust += (np.log(z + 1) / (capacity + 1)) * z
            priorities[i] *= adjust
    return priorities
